class Solution:
  def power(self, base: int, exp: int, mod: int) -> int:
    if exp == 0:
      return 1
    if exp % 2 == 0:
      half_pow = self.power(base, exp // 2, mod)
      return (half_pow * half_pow) % mod
    else:
      half_pow = self.power(base, exp // 2, mod)
      return ((base * half_pow) % mod * half_pow) % mod

