class Solution {
 public:
  int power(int base, int exp, int mod) {
    if (exp == 0) return 1;
    if (exp % 2 == 0) return (power(base, exp / 2, mod) * power(base, exp / 2, mod)) % mod;
    else return ((base * power(base, exp - 1, mod)) % mod);
  }
};
